VALUES
  ('optician-moex-01429', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡的消毒方法，何者敘述錯誤？', '["化學消毒的問題為其防腐劑的使用，例如氯己定（chlorhexidine），會使許多人有敏感性反應", "熱消毒為最有效且最便宜之消毒法，可以對抗阿米巴原蟲及HIV病毒且可搭配無防腐劑之溶液", "氧化消毒（HO）浸泡5～15分鐘可對抗真菌及阿米巴原蟲，直接接觸角膜可能會引起點狀角膜炎", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
